func TestNovelListingCommandIsExecutable(t *testing.T) {
	cmd := newNovelListingCmd(&rootFlags{})
	if cmd.Use == "" || cmd.RunE == nil {
		t.Fatalf("command is not executable: %#v", cmd)
	}
	found, _, err := cmd.Find([]string{"gaps"})
	if err != nil {
		t.Fatalf("Find(gaps) error = %v", err)
	}
	if found == nil || found.Name() != "gaps" || found.Use == "" || found.RunE == nil {
		t.Fatalf("gaps subcommand is not executable: %#v", found)
	}
}

