func TestNovelListingGapsReportsMissingTitleAndTagTerms(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		switch r.URL.Path {
		case "/api/keyword-tool/stats":
			_, _ = w.Write([]byte(`{"avg_searches":100}`))
		case "/api/keyword-tool/top-listings":
			_, _ = w.Write([]byte(`{"data":[{"tags":["ceramic mug","pottery gift"]}]}`))
		case "/api/keyword-tool/etsy-tags":
			_, _ = w.Write([]byte(`{"data":[{"tag":"ceramic mug"},{"tag":"pottery gift"}]}`))
		case "/api/keyword-tool/related-searches", "/api/keyword-tool/near-matches":
			_, _ = w.Write([]byte(`{"data":[]}`))
		default:
			http.NotFound(w, r)
		}
	}))
	defer server.Close()

	t.Setenv("ERANK_BASE_URL", server.URL)
	t.Setenv("ERANK_XSRF_TOKEN", "test-token")

	flags := &rootFlags{
		asJSON:     true,
		noCache:    true,
		configPath: filepath.Join(t.TempDir(), "config.toml"),
	}
	cmd := newNovelListingGapsCmd(flags)
	var out bytes.Buffer
	cmd.SetOut(&out)
	cmd.SetArgs([]string{"ceramic mug", "--title", "minimalist vase", "--tags", "coffee cup"})

	if err := cmd.Execute(); err != nil {
		t.Fatalf("Execute() error = %v", err)
	}

	var got struct {
		MissingSignals []consensusTag `json:"missing_signals"`
	}
	if err := json.Unmarshal(out.Bytes(), &got); err != nil {
		t.Fatalf("unmarshal output %q: %v", out.String(), err)
	}
	if len(got.MissingSignals) != 2 {
		t.Fatalf("missing_signals = %#v, want 2 missing terms", got.MissingSignals)
	}
	if got.MissingSignals[0].Tag != "ceramic mug" || got.MissingSignals[1].Tag != "pottery gift" {
		t.Fatalf("missing_signals = %#v, want ceramic mug and pottery gift", got.MissingSignals)
	}
}
